// ── Extract contact ID from associations response ──
const results = $input.first().json.results;

if (!results || results.length === 0) {
  throw new Error(
    'No contact is associated with this HubSpot deal. ' +
    'Please associate at least one contact before marking as Closed Won.'
  );
}

const contactId = results[0].id;

// Pull deal data fetched two nodes ago
const deal = $('🏷️ HTTP - Get Deal Details').first().json;

return {
  contactId,
  dealId:    deal.id,
  dealName:  deal.properties.dealname  || 'Professional Services',
  amount:    deal.properties.amount    || '0',
  closeDate: deal.properties.closedate || new Date().toISOString().split('T')[0]
};

// ── Build invoice data + beautifully styled HTML ──
const contactProps = $input.first().json.properties;
const contactId    = $input.first().json.id;
const prev         = $('⚙️ Code - Extract Contact ID').first().json;

// ── Generate invoice number ──
const pad = (n) => String(n).padStart(4, '0');
const invoiceNumber = 'INV-' + new Date().getFullYear() + '-' + pad(Math.floor(Math.random() * 9000) + 1000);
const issueDate     = new Date().toISOString().split('T')[0];
const dueDate       = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

// ── Contact & deal info ──
const firstName    = contactProps.firstname || '';
const lastName     = contactProps.lastname  || '';
const contactName  = `${firstName} ${lastName}`.trim() || 'Valued Customer';
const contactEmail = contactProps.email   || '';
const company      = contactProps.company || '';
const phone        = contactProps.phone   || 'N/A';
const amount       = parseFloat(prev.amount || '0');
const dealName     = prev.dealName;

const fmt = (n) => n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const formattedAmount = fmt(amount);
const year = new Date().getFullYear();

// ── Build HTML invoice ──
const htmlContent = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  * { margin:0; padding:0; box-sizing:border-box; }
  body { font-family:'Segoe UI',Arial,sans-serif; color:#2d3748; background:#fff; }
  .wrap { max-width:780px; margin:0 auto; padding:48px; }
  .header { display:flex; justify-content:space-between; align-items:flex-start;
            padding-bottom:28px; border-bottom:4px solid #4F46E5; margin-bottom:36px; }
  .brand-name { font-size:24px; font-weight:800; color:#4F46E5; letter-spacing:-0.5px; }
  .brand-sub  { font-size:12px; color:#718096; margin-top:5px; line-height:1.6; }
  .inv-badge  { text-align:right; }
  .inv-label  { font-size:30px; font-weight:900; color:#4F46E5; letter-spacing:4px; }
  .inv-num    { font-size:15px; color:#718096; margin-top:4px; font-weight:600; }
  .grid       { display:grid; grid-template-columns:1fr 1fr; gap:20px; margin-bottom:32px; }
  .box        { background:#F7F8FC; border-radius:10px; padding:20px; }
  .box h4     { font-size:10px; text-transform:uppercase; letter-spacing:1.5px;
                color:#A0AEC0; margin-bottom:10px; }
  .box p      { font-size:13.5px; color:#4A5568; line-height:1.8; }
  .box .bold  { font-weight:700; font-size:15px; color:#2d3748; }
  .status-unpaid { display:inline-block; background:#FFF5F5; color:#E53E3E;
                   padding:2px 10px; border-radius:20px; font-weight:700; font-size:12px; }
  table       { width:100%; border-collapse:collapse; margin-bottom:8px; }
  thead tr    { background:#4F46E5; }
  thead th    { color:#fff; padding:13px 16px; text-align:left;
                font-size:12px; font-weight:600; letter-spacing:0.8px; text-transform:uppercase; }
  tbody tr    { border-bottom:1px solid #EDF2F7; }
  tbody td    { padding:13px 16px; font-size:14px; color:#4A5568; }
  .sub-row td { padding:8px 16px; color:#718096; font-size:13px; }
  .total-row td { padding:15px 16px; background:#F7F8FC; font-weight:700;
                  font-size:16px; border-top:2px solid #4F46E5; }
  .total-amt  { color:#4F46E5; font-size:20px; }
  .pay-box    { background:#EBF8FF; border:1px solid #BEE3F8; border-radius:10px;
                padding:18px 22px; margin:20px 0 32px; }
  .pay-box h4 { color:#2B6CB0; font-size:13px; font-weight:700; margin-bottom:8px; }
  .pay-box p  { color:#2C5282; font-size:13px; line-height:1.7; }
  .footer     { margin-top:36px; padding-top:20px; border-top:1px solid #EDF2F7;
                text-align:center; color:#A0AEC0; font-size:11.5px; line-height:1.8; }
</style>
</head>
<body>
<div class="wrap">

  <div class="header">
    <div>
      <div class="brand-name">YOUR COMPANY NAME</div>
      <div class="brand-sub">
        123 Business St, City, State 12345<br>
        user@example.com &nbsp;|&nbsp; +1234567890
      </div>
    </div>
    <div class="inv-badge">
      <div class="inv-label">INVOICE</div>
      <div class="inv-num">${invoiceNumber}</div>
    </div>
  </div>

  <div class="grid">
    <div class="box">
      <h4>Bill To</h4>
      <p class="bold">${contactName}</p>
      <p>${company}</p>
      <p>${contactEmail}</p>
      <p>${phone}</p>
    </div>
    <div class="box">
      <h4>Invoice Details</h4>
      <p><strong>Invoice No:</strong> ${invoiceNumber}</p>
      <p><strong>Issue Date:</strong> ${issueDate}</p>
      <p><strong>Due Date:</strong> ${dueDate}</p>
      <p><strong>Status:</strong> <span class="status-unpaid">UNPAID</span></p>
    </div>
  </div>

  <table>
    <thead>
      <tr>
        <th>Description</th>
        <th style="width:80px">Qty</th>
        <th style="width:150px">Unit Price</th>
        <th style="width:150px">Amount</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td>${dealName}</td>
        <td>1</td>
        <td>$${formattedAmount}</td>
        <td>$${formattedAmount}</td>
      </tr>
      <tr class="sub-row">
        <td colspan="3" style="text-align:right">Subtotal</td>
        <td>$${formattedAmount}</td>
      </tr>
      <tr class="sub-row">
        <td colspan="3" style="text-align:right">Tax (0%)</td>
        <td>$0.00</td>
      </tr>
      <tr class="total-row">
        <td colspan="3" style="text-align:right">Total Amount Due</td>
        <td class="total-amt">$${formattedAmount}</td>
      </tr>
    </tbody>
  </table>

  <div class="pay-box">
    <h4>💳 Payment Instructions</h4>
    <p>
      Please make payment within 30 days of the invoice date.<br>
      Reference invoice number <strong>${invoiceNumber}</strong> in your payment.<br>
      Bank Transfer: Account <strong>1234-5678</strong> &nbsp;|&nbsp; Routing: <strong>021000021</strong>
    </p>
  </div>

  <div class="footer">
    Thank you for your business! Questions? Contact user@example.com<br>
    © ${year} Your Company Name. All rights reserved. &nbsp;|&nbsp; Payment terms: Net 30
  </div>

</div>
</body>
</html>`;

return {
  invoice_number:   invoiceNumber,
  issue_date:       issueDate,
  due_date:         dueDate,
  amount,
  formatted_amount: formattedAmount,
  deal_name:        dealName,
  contact_name:     contactName,
  contact_email:    contactEmail,
  company,
  phone,
  deal_id:    prev.dealId,
  contact_id: contactId,
  html_content: htmlContent
};

